+:root {
+  /* {{THEME_VARS}} */
+  /* {{BODY_BG_DECL}} */
+  /* {{CONTAINER_BG_DECL}} */
+  /* {{INFO_BG_DECL}} */
+}
+
+* {
+  margin: 0;
+  padding: 0;
+  box-sizing: border-box;
+}
+
+:root {
+  --line-height: 18px; /* 12px font * 1.5 */
+}
+
+body {
+  font-family:
+    ui-monospace, "Cascadia Code", "Source Code Pro", Menlo, Consolas, "DejaVu Sans Mono", monospace;
+  font-size: 12px;
+  line-height: var(--line-height);
+  color: var(--text);
+  background: var(--body-bg);
+}
+
+#app {
+  display: flex;
+  min-height: 100vh;
+}
+
+/* Sidebar */
+#sidebar {
+  width: 400px;
+  background: var(--container-bg);
+  flex-shrink: 0;
+  display: flex;
+  flex-direction: column;
+  position: sticky;
+  top: 0;
+  height: 100vh;
+  border-right: 1px solid var(--dim);
+}
+
+.sidebar-header {
+  padding: 8px 12px;
+  flex-shrink: 0;
+}
+
+.sidebar-controls {
+  padding: 8px 8px 4px 8px;
+}
+
+.sidebar-search {
+  width: 100%;
+  box-sizing: border-box;
+  padding: 4px 8px;
+  font-size: 11px;
+  font-family: inherit;
+  background: var(--body-bg);
+  color: var(--text);
+  border: 1px solid var(--dim);
+  border-radius: 3px;
+}
+
+.sidebar-filters {
+  display: flex;
+  padding: 4px 8px 8px 8px;
+  gap: 4px;
+  align-items: center;
+  flex-wrap: wrap;
+}
+
+.sidebar-search:focus {
+  outline: none;
+  border-color: var(--accent);
+}
+
+.sidebar-search::placeholder {
+  color: var(--muted);
+}
+
+.filter-btn {
+  padding: 3px 8px;
+  font-size: 10px;
+  font-family: inherit;
+  background: transparent;
+  color: var(--muted);
+  border: 1px solid var(--dim);
+  border-radius: 3px;
+  cursor: pointer;
+}
+
+.filter-btn:hover {
+  color: var(--text);
+  border-color: var(--text);
+}
+
+.filter-btn.active {
+  background: var(--accent);
+  color: var(--body-bg);
+  border-color: var(--accent);
+}
+
+.sidebar-close {
+  display: none;
+  padding: 3px 8px;
+  font-size: 12px;
+  font-family: inherit;
+  background: transparent;
+  color: var(--muted);
+  border: 1px solid var(--dim);
+  border-radius: 3px;
+  cursor: pointer;
+  margin-left: auto;
+}
+
+.sidebar-close:hover {
+  color: var(--text);
+  border-color: var(--text);
+}
+
+.tree-container {
+  flex: 1;
+  overflow: auto;
+  padding: 4px 0;
+}
+
+.tree-node {
+  padding: 0 8px;
+  cursor: pointer;
+  display: flex;
+  align-items: baseline;
+  font-size: 11px;
+  line-height: 13px;
+  white-space: nowrap;
+}
+
+.tree-node:hover {
+  background: var(--selectedBg);
+}
+
+.tree-node.active {
+  background: var(--selectedBg);
+}
+
+.tree-node.active .tree-content {
+  font-weight: bold;
+}
+
+.tree-node.in-path {
+  background: color-mix(in srgb, var(--accent) 10%, transparent);
+}
+
+.tree-node:not(.in-path) {
+  opacity: 0.5;
+}
+
+.tree-node:not(.in-path):hover {
+  opacity: 1;
+}
+
+.tree-prefix {
+  color: var(--muted);
+  flex-shrink: 0;
+  font-family: monospace;
+  white-space: pre;
+}
+
+.tree-marker {
+  color: var(--accent);
+  flex-shrink: 0;
+}
+
+.tree-content {
+  color: var(--text);
+}
+
+.tree-role-user {
+  color: var(--accent);
+}
+
+.tree-role-assistant {
+  color: var(--success);
+}
+
+.tree-role-tool {
+  color: var(--muted);
+}
+
+.tree-muted {
+  color: var(--muted);
+}
+
+.tree-error {
+  color: var(--error);
+}
+
+.tree-compaction {
+  color: var(--borderAccent);
+}
+
+.tree-branch-summary {
+  color: var(--warning);
+}
+
+.tree-custom-message {
+  color: var(--customMessageLabel);
+}
+
+.tree-status {
+  padding: 4px 12px;
+  font-size: 10px;
+  color: var(--muted);
+  flex-shrink: 0;
+}
+
+/* Main content */
+#content {
+  flex: 1;
+  overflow-y: auto;
+  padding: var(--line-height) calc(var(--line-height) * 2);
+  display: flex;
+  flex-direction: column;
+  align-items: center;
+}
+
+#content > * {
+  width: 100%;
+  max-width: 800px;
+}
+
+/* Help bar */
+.help-bar {
+  font-size: 11px;
+  color: var(--warning);
+  margin-bottom: var(--line-height);
+  display: flex;
+  align-items: center;
+  gap: 12px;
+}
+
+.download-json-btn {
+  font-size: 10px;
+  padding: 2px 8px;
+  background: var(--container-bg);
+  border: 1px solid var(--border);
+  border-radius: 3px;
+  color: var(--text);
+  cursor: pointer;
+  font-family: inherit;
+}
+
+.download-json-btn:hover {
+  background: var(--hover);
+  border-color: var(--borderAccent);
+}
+
+/* Header */
+.header {
+  background: var(--container-bg);
+  border-radius: 4px;
+  padding: var(--line-height);
+  margin-bottom: var(--line-height);
+}
+
+.header h1 {
+  font-size: 12px;
+  font-weight: bold;
+  color: var(--borderAccent);
+  margin-bottom: var(--line-height);
+}
+
+.header-info {
+  display: flex;
+  flex-direction: column;
+  gap: 0;
+  font-size: 11px;
+}
+
+.info-item {
+  color: var(--dim);
+  display: flex;
+  align-items: baseline;
+}
+
+.info-label {
+  font-weight: 600;
+  margin-right: 8px;
+  min-width: 100px;
+}
+
+.info-value {
+  color: var(--text);
+  flex: 1;
+}
+
+/* Messages */
+#messages {
+  display: flex;
+  flex-direction: column;
+  gap: var(--line-height);
+}
+
+.message-timestamp {
+  font-size: 10px;
+  color: var(--dim);
+  opacity: 0.8;
+}
+
+.user-message {
+  background: var(--userMessageBg);
+  color: var(--userMessageText);
+  padding: var(--line-height);
+  border-radius: 4px;
+  position: relative;
+}
+
+.assistant-message {
+  padding: 0;
+  position: relative;
+}
+
+/* Copy link button - appears on hover */
+.copy-link-btn {
+  position: absolute;
+  top: 8px;
+  right: 8px;
+  width: 28px;
+  height: 28px;
+  padding: 6px;
+  background: var(--container-bg);
+  border: 1px solid var(--dim);
+  border-radius: 4px;
+  color: var(--muted);
+  cursor: pointer;
+  opacity: 0;
+  transition:
+    opacity 0.15s,
+    background 0.15s,
+    color 0.15s;
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  z-index: 10;
+}
+
+.user-message:hover .copy-link-btn,
+.assistant-message:hover .copy-link-btn {
+  opacity: 1;
+}
+
+.copy-link-btn:hover {
+  background: var(--accent);
+  color: var(--body-bg);
+  border-color: var(--accent);
+}
+
+.copy-link-btn.copied {
+  background: var(--success, #22c55e);
+  color: white;
+  border-color: var(--success, #22c55e);
+}
+
+/* Highlight effect for deep-linked messages */
+.user-message.highlight,
+.assistant-message.highlight {
+  animation: highlight-pulse 2s ease-out;
+}
+
+@keyframes highlight-pulse {
+  0% {
+    box-shadow: 0 0 0 3px var(--accent);
+  }
+  100% {
+    box-shadow: 0 0 0 0 transparent;
+  }
+}
+
+.assistant-message > .message-timestamp {
+  padding-left: var(--line-height);
+}
+
+.assistant-text {
+  padding: var(--line-height);
+  padding-bottom: 0;
+}
+
+.message-timestamp + .assistant-text,
+.message-timestamp + .thinking-block {
+  padding-top: 0;
+}
